"use client";

import { type SidebarProps, Sidebar as SidebarRoot } from "./sidebar";
import { SidebarContent, type SidebarContentProps } from "./sidebar-content";
import type { SidebarState } from "./sidebar-context";
import { SidebarFooter, type SidebarFooterProps } from "./sidebar-footer";
import { SidebarHeader, type SidebarHeaderProps } from "./sidebar-header";
import type { SidebarIntent } from "./sidebar-intent";
import {
  SidebarItem,
  type SidebarItemAsAnchorProps,
  type SidebarItemAsButtonProps,
  type SidebarItemProps,
  type SidebarItemRenderProps,
} from "./sidebar-item";
import { SidebarItemBadge, type SidebarItemBadgeProps } from "./sidebar-item-badge";
import { SidebarItemLabel, type SidebarItemLabelProps } from "./sidebar-item-label";
import {
  SIDEBAR_STATE_COOKIE,
  SidebarProvider,
  type SidebarProviderProps,
} from "./sidebar-provider";
import { SidebarSection, type SidebarSectionProps } from "./sidebar-section";
import { SidebarSectionContent, type SidebarSectionContentProps } from "./sidebar-section-content";
import {
  SidebarSectionTitle,
  type SidebarSectionTitleHeadingLevel,
  type SidebarSectionTitleProps,
} from "./sidebar-section-title";
import { SidebarTrigger, type SidebarTriggerProps } from "./sidebar-trigger";
import type { SidebarVariant } from "./sidebar-variants";

const Sidebar = Object.assign(SidebarRoot, {
  Provider: SidebarProvider,
  Trigger: SidebarTrigger,
  Header: SidebarHeader,
  Content: SidebarContent,
  Section: SidebarSection,
  SectionTitle: SidebarSectionTitle,
  SectionContent: SidebarSectionContent,
  Item: SidebarItem,
  ItemLabel: SidebarItemLabel,
  ItemBadge: SidebarItemBadge,
  Footer: SidebarFooter,
});

export { Sidebar, type SidebarProps };
export { SidebarProvider, type SidebarProviderProps, SIDEBAR_STATE_COOKIE };
export { SidebarTrigger, type SidebarTriggerProps };
export { SidebarHeader, type SidebarHeaderProps };
export { SidebarContent, type SidebarContentProps };
export { SidebarSection, type SidebarSectionProps };
export { SidebarSectionContent, type SidebarSectionContentProps };
export { SidebarSectionTitle, type SidebarSectionTitleProps, type SidebarSectionTitleHeadingLevel };
export {
  SidebarItem,
  type SidebarItemProps,
  type SidebarItemAsButtonProps,
  type SidebarItemAsAnchorProps,
  type SidebarItemRenderProps,
};
export { SidebarItemLabel, type SidebarItemLabelProps };
export { SidebarItemBadge, type SidebarItemBadgeProps };
export { SidebarFooter, type SidebarFooterProps };
export { useSidebar } from "./sidebar-context";
export type { SidebarVariant, SidebarIntent, SidebarState };

"use client";

import { type ComponentProps, type ReactNode, useMemo } from "react";
import { cn } from "@/lib/utils";
import { Dialog, DialogContent } from "../dialog";
import { SidebarChromeContext, useOptionalSidebar, useSidebar } from "./sidebar-context";
import { SidebarProvider } from "./sidebar-provider";
import { type SidebarVariant, sidebarContainerVariants } from "./sidebar-variants";

/** Props for sidebar. */
export interface SidebarProps extends ComponentProps<"nav"> {
  /**
   * Visual variant. "caret" reserves a chevron marker slot shown on the active row;
   * "inverted" full-bleeds the active row with bg-foreground; "bar" draws a 2px left edge with
   * a soft fill on active; "terminal" shows the chevron prompt on the active item and draws a
   * 1px hairline left rail with no background fill; "tree" renders bold section headers with
   * stroke-chevron folds and single-hairline connectors (trunk/tick/corner) with a soft active
   * fill. Propagated to items via context and exposed as data-variant on the nav root.
   */
  variant?: SidebarVariant;
  /**
   * When true, renders a small intent dot before each item label and derives intent from the
   * item value via the built-in dictionary unless overridden by an explicit intent prop on the
   * item. Color is decoration only (WCAG 1.4.1) - pair with a text/glyph cue.
   */
  autoTone?: boolean;
  /**
   * When true, always render inline navigation even on mobile. Use when a parent layout (for
   * example an app shell drawer) already owns the mobile presentation.
   */
  embedded?: boolean;
  /** Sidebar subparts (Header, Content, Footer, Trigger). */
  children: ReactNode;
}

function SidebarNav({
  ref,
  variant,
  autoTone,
  className,
  "aria-label": ariaLabel,
  children,
  ...rest
}: ComponentProps<"nav"> & {
  variant: SidebarVariant;
  autoTone: boolean;
}) {
  const { state } = useSidebar();
  return (
    <nav
      ref={ref}
      aria-label={ariaLabel ?? "Primary"}
      data-slot="sidebar"
      data-variant={variant}
      data-state={state}
      data-auto-tone={autoTone || undefined}
      {...rest}
      className={cn(sidebarContainerVariants({ state }), className)}
    >
      {children}
    </nav>
  );
}

function SidebarShell({
  ref,
  variant,
  autoTone,
  embedded,
  className,
  children,
  "aria-label": ariaLabel,
  ...rest
}: {
  variant: SidebarVariant;
  autoTone: boolean;
  embedded: boolean;
  className?: string;
  children: ReactNode;
} & ComponentProps<"nav">) {
  const { state, isMobile, onStateChange } = useSidebar();
  const open = state !== "hidden";

  if (isMobile && !embedded) {
    // Mobile: render the same chrome inside a Dialog sheet. Width is fixed
    // by the sheet wrapper (86vw / max 320px) and the inner nav fills it.
    return (
      <Dialog open={open} onOpenChange={(next) => onStateChange(next ? "open" : "hidden")}>
        <DialogContent
          aria-label={ariaLabel ?? "Primary navigation"}
          className="!max-w-[min(86vw,320px)] !h-[100dvh] !max-h-[100dvh] !m-0 !border-r border-border !rounded-none p-0 pb-[env(safe-area-inset-bottom)]"
          frame="none"
        >
          <SidebarNav
            ref={ref}
            variant={variant}
            autoTone={autoTone}
            className={cn("h-full w-full", className)}
            data-mobile="true"
            aria-label={ariaLabel}
            {...rest}
          >
            {children}
          </SidebarNav>
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <SidebarNav
      ref={ref}
      variant={variant}
      autoTone={autoTone}
      className={className}
      aria-label={ariaLabel}
      {...rest}
    >
      {children}
    </SidebarNav>
  );
}

/** Root nav element (standalone or within SidebarProvider). Owns variant + autoTone. */
export function Sidebar({
  ref,
  variant,
  autoTone = false,
  embedded = false,
  children,
  className,
  ...rest
}: SidebarProps) {
  const existingContext = useOptionalSidebar();
  const resolvedVariant = variant ?? "caret";
  const chromeValue = useMemo(
    () => ({ variant: resolvedVariant, autoTone }),
    [resolvedVariant, autoTone],
  );

  const chrome = (
    <SidebarChromeContext value={chromeValue}>
      <SidebarShell
        ref={ref}
        variant={resolvedVariant}
        autoTone={autoTone}
        embedded={embedded}
        className={className}
        {...rest}
      >
        {children}
      </SidebarShell>
    </SidebarChromeContext>
  );

  if (existingContext) return chrome;
  // The implicit fallback provider does not bind the global Cmd/Ctrl+B hotkey:
  // global keys are an app-level contract, and casually mounted sidebars
  // (docs demos, embedded shells) must not stack listeners on one page. Mount
  // SidebarProvider explicitly to opt in.
  return <SidebarProvider shortcutKey={null}>{chrome}</SidebarProvider>;
}

"use client";

import { createContext, useContext } from "react";
import type { SidebarVariant } from "./sidebar-variants";

/** Allowed sidebar state values. */
export type SidebarState = "open" | "rail" | "hidden";

/** Context value shared by sidebar. */
export interface SidebarContextValue {
  /** state used by sidebar. */
  state: SidebarState;
  /** DOM id for content. */
  contentId: string;
  /** Whether sidebar is mobile. */
  isMobile: boolean;
  /** Called when state change occurs. */
  onStateChange: (state: SidebarState) => void;
  /** Toggles sidebar. */
  toggleSidebar: () => void;
  /** Toggles hidden. */
  toggleHidden: () => void;
}

/** React context backing sidebar. */
export const SidebarContext = createContext<SidebarContextValue | undefined>(undefined);

/** Provides sidebar behavior. */
export function useSidebar() {
  const context = useContext(SidebarContext);
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider or Sidebar");
  }
  return context;
}

/** Provides optional sidebar behavior. */
export function useOptionalSidebar() {
  return useContext(SidebarContext);
}

/** Context value shared by sidebar chrome. */
export interface SidebarChromeContextValue {
  /**
   * Visual variant. "caret" reserves a chevron marker slot shown on the active row;
   * "inverted" full-bleeds the active row with bg-foreground; "bar" draws a 2px left edge with
   * a soft fill on active; "terminal" shows the chevron prompt on the active item and draws a
   * 1px hairline left rail with no background fill; "tree" renders bold section headers with
   * stroke-chevron folds and single-hairline connectors (trunk/tick/corner) with a soft active
   * fill. Propagated to items via context and exposed as data-variant on the nav root.
   */
  variant: SidebarVariant;
  /**
   * When true, renders a small intent dot before each item label and derives intent from the
   * item value via the built-in dictionary unless overridden by an explicit intent prop on the
   * item. Color is decoration only (WCAG 1.4.1) - pair with a text/glyph cue.
   */
  autoTone: boolean;
}

/** React context backing sidebar chrome. */
export const SidebarChromeContext = createContext<SidebarChromeContextValue>({
  variant: "caret",
  autoTone: false,
});

/** Provides sidebar chrome behavior. */
export function useSidebarChrome() {
  return useContext(SidebarChromeContext);
}

"use client";

import { isEditableElement } from "@/hooks/utils/element-guards";
import { type ReactNode, useCallback, useEffect, useId, useMemo, useRef } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useIsMobile } from "@/hooks/use-is-mobile";
import { SidebarContext, type SidebarState } from "./sidebar-context";

export interface SidebarProviderProps {
  /**
   * Documented exception to the `value`/`onChange` control convention: the sidebar exposes a
   * tri-state value (`"open" | "rail" | "hidden"`), so the boolean
   * `collapsed`/`onCollapsedChange` shape cannot represent it. `state` and `onStateChange` are
   * the semantic names for this tri-state control.
   */
  state?: SidebarState;
  /** Initial visibility state for uncontrolled use. */
  defaultState?: SidebarState;
  /** Fired when the visibility state changes (controlled and uncontrolled). */
  onStateChange?: (state: SidebarState) => void;
  /**
   * Viewport width (px) below which the sidebar collapses into a mobile sheet. Default matches
   * Tailwind lg.
   */
  breakpoint?: number;
  /**
   * Case-insensitive hotkey. Cmd/Ctrl+<key> cycles open ↔ rail; Shift+Cmd/Ctrl+<key> toggles
   * hidden. Pass null to disable.
   */
  shortcutKey?: string | null;
  /** Sidebar and main content that need access to the state via useSidebar(). */
  children: ReactNode;
}

export const SIDEBAR_STATE_COOKIE = "dg_sidebar_state";

// keys' isEditableElement excludes <select> (a list control, not a text editor);
// the sidebar shortcut must still defer to a focused select, so this thin
// wrapper adds that case while keeping isEditableElement's correct exclusion of
// non-editable input types (button/checkbox/radio/submit). The HTMLSelectElement
// constructor is resolved through the target's ownerDocument.defaultView rather
// than the bare global so cross-document focus is handled correctly.
function isShortcutEditableTarget(target: EventTarget | null): boolean {
  if (isEditableElement(target)) return true;
  const view = (target as { ownerDocument?: Document } | null)?.ownerDocument?.defaultView;
  return Boolean(view && target instanceof view.HTMLSelectElement);
}

export function SidebarProvider({
  state: controlledState,
  defaultState = "open",
  onStateChange,
  breakpoint = 1024,
  shortcutKey = "b",
  children,
}: SidebarProviderProps) {
  const sidebarId = useId();
  const anchorRef = useRef<HTMLSpanElement>(null);
  const [state, setState] = useControllableState<SidebarState>({
    value: controlledState,
    defaultValue: defaultState,
    onChange: onStateChange,
  });
  const isMobile = useIsMobile(breakpoint);

  const toggleSidebar = useCallback(() => {
    setState((prev) => (prev === "open" ? "rail" : "open"));
  }, [setState]);

  const toggleHidden = useCallback(() => {
    setState((prev) => (prev === "hidden" ? "open" : "hidden"));
  }, [setState]);

  useEffect(() => {
    if (!shortcutKey) return;
    const view = anchorRef.current?.ownerDocument.defaultView;
    if (!view) return;
    const normalizedKey = shortcutKey.toLowerCase();
    const handler = (event: KeyboardEvent) => {
      if (event.key.toLowerCase() !== normalizedKey) return;
      if (!(event.metaKey || event.ctrlKey)) return;
      if (isShortcutEditableTarget(event.target)) return;
      event.preventDefault();
      if (event.shiftKey) {
        toggleHidden();
      } else {
        toggleSidebar();
      }
    };
    view.addEventListener("keydown", handler);
    return () => view.removeEventListener("keydown", handler);
  }, [shortcutKey, toggleSidebar, toggleHidden]);

  const contextValue = useMemo(
    () => ({
      state,
      contentId: `${sidebarId}-content`,
      isMobile,
      onStateChange: setState,
      toggleSidebar,
      toggleHidden,
    }),
    [state, isMobile, setState, sidebarId, toggleSidebar, toggleHidden],
  );

  return (
    <SidebarContext value={contextValue}>
      {/* Zero-footprint anchor: resolves the owning window so the global
          shortcut listener binds to the sidebar's ownerDocument.defaultView
          instead of assuming the top-level window. */}
      <span ref={anchorRef} hidden aria-hidden="true" />
      {children}
    </SidebarContext>
  );
}

"use client";

import type { ButtonHTMLAttributes, Ref } from "react";
import { cn } from "@/lib/utils";
import { useSidebar } from "./sidebar-context";

export interface SidebarTriggerProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLButtonElement>;
}

/** Toggle button. Desktop cycles open ↔ rail; mobile cycles open ↔ hidden. */
export function SidebarTrigger({
  ref,
  className,
  onClick,
  children,
  "aria-label": ariaLabel,
  ...props
}: SidebarTriggerProps) {
  const { state, isMobile, contentId, toggleSidebar, onStateChange } = useSidebar();
  const isOpen = isMobile ? state !== "hidden" : state === "open";
  const visualState: "open" | "collapsed" = isOpen ? "open" : "collapsed";
  let labelDefault = isOpen ? "Collapse sidebar" : "Expand sidebar";
  if (isMobile) {
    labelDefault = isOpen ? "Close navigation" : "Open navigation";
  }

  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    onClick?.(event);
    if (event.defaultPrevented) return;
    if (isMobile) {
      onStateChange(isOpen ? "hidden" : "open");
    } else {
      toggleSidebar();
    }
  };

  return (
    <button
      {...props}
      ref={ref}
      type="button"
      aria-controls={props["aria-controls"] ?? contentId}
      aria-expanded={isOpen}
      aria-label={ariaLabel ?? labelDefault}
      data-state={visualState}
      className={cn("inline-flex min-h-6 min-w-6 items-center justify-center font-mono", className)}
      onClick={handleClick}
    >
      {children ?? <span aria-hidden="true">{isOpen ? "[×]" : "[≡]"}</span>}
    </button>
  );
}

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";

/** Props for sidebar header. */
export interface SidebarHeaderProps extends ComponentProps<"div"> {}

/** Top section with bottom border. */
export function SidebarHeader({ ref, children, className, ...props }: SidebarHeaderProps) {
  return (
    // min-h-11 pins the single-line header to the system's h-11 control row
    // regardless of inherited line-height, so shell headers beside the sidebar
    // can align their hairline to it. Taller content still grows via py-2.
    <div
      ref={ref}
      className={cn(
        "flex min-h-11 items-center px-4 py-2 border-b border-border shrink-0",
        className,
      )}
      {...props}
    >
      {children}
    </div>
  );
}

"use client";

import { type ComponentProps, type KeyboardEvent, useRef } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useNavigation } from "@/hooks/use-navigation";
import { cn } from "@/lib/utils";
import { useSidebar } from "./sidebar-context";

/** Props for sidebar content. */
export interface SidebarContentProps extends ComponentProps<"div"> {}

/** Scrollable middle area. */
export function SidebarContent({
  ref,
  children,
  className,
  onKeyDown,
  ...props
}: SidebarContentProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(containerRef, ref);
  const { state, contentId } = useSidebar();
  const hidden = state === "hidden";
  const ariaHidden = hidden ? true : props["aria-hidden"];

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "button",
    orientation: "vertical",
    wrap: true,
    moveFocus: true,
    scopeToContainer: true,
  });

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    onKeyDown?.(e);
    if (!e.defaultPrevented) navKeyDown(e);
  };

  return (
    <div
      {...props}
      ref={composedRef}
      id={props.id ?? contentId}
      aria-hidden={ariaHidden}
      inert={hidden ? true : undefined}
      hidden={hidden || props.hidden || undefined}
      data-state={state}
      className={cn(
        "flex-1 overflow-y-auto p-4",
        // Rail mode: zero horizontal padding so items center inside the 48px
        // rail. Vertical padding stays so the first/last items breathe.
        "group-data-[state=rail]/sidebar:px-0",
        className,
      )}
      onKeyDown={handleKeyDown}
    >
      {children}
    </div>
  );
}

"use client";

import {
  Children,
  type ComponentProps,
  isValidElement,
  type ReactNode,
  useId,
  useMemo,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { cn } from "@/lib/utils";
import { SidebarSectionContext } from "./sidebar-section-context";
import { SidebarSectionTitle } from "./sidebar-section-title";

/** Props for sidebar section. */
export interface SidebarSectionProps extends ComponentProps<"div"> {
  /**
   * When true, Sidebar.SectionTitle becomes a disclosure toggle that expands/collapses the
   * section.
   */
  collapsible?: boolean;
  /** Controlled open state for the section. */
  open?: boolean;
  /** Fired when the section open state changes. */
  onOpenChange?: (open: boolean) => void;
  /** Initial open state for the section. */
  defaultOpen?: boolean;
}

/** Grouping container (optional collapsible, supports controlled open/onOpenChange) */
export function SidebarSection({
  ref,
  collapsible = false,
  open: controlledOpen,
  onOpenChange,
  defaultOpen = true,
  className,
  children,
  "aria-labelledby": ariaLabelledBy,
  ...rest
}: SidebarSectionProps) {
  const titleId = useId();
  const panelId = useId();
  const labelSourceId =
    ariaLabelledBy ?? (containsSidebarSectionTitleElement(children) ? titleId : undefined);

  const [isOpen, setIsOpen] = useControllableState<boolean>({
    value: controlledOpen,
    defaultValue: defaultOpen,
    onChange: onOpenChange,
  });

  const contextValue = useMemo(
    () => ({
      collapsible,
      open: isOpen,
      onToggle: () => setIsOpen((prev) => !prev),
      titleId,
      panelId,
    }),
    [collapsible, isOpen, setIsOpen, titleId, panelId],
  );

  return (
    <SidebarSectionContext value={contextValue}>
      {/* biome-ignore lint/a11y/useSemanticElements: role="group" labels a collapsible sidebar section; <fieldset> is for form controls and is not appropriate here. */}
      <div
        {...rest}
        ref={ref}
        role="group"
        aria-labelledby={labelSourceId}
        data-state={isOpen ? "open" : "closed"}
        className={cn("mb-4", className)}
      >
        {children}
      </div>
    </SidebarSectionContext>
  );
}

function containsSidebarSectionTitleElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === SidebarSectionTitle) return true;
    return containsSidebarSectionTitleElement(child.props.children);
  });
}

"use client";

import { createContext, useContext } from "react";

/** Context value shared by sidebar section. */
export interface SidebarSectionContextValue {
  /**
   * When true, Sidebar.SectionTitle becomes a disclosure toggle that expands/collapses the
   * section.
   */
  collapsible: boolean;
  /** Controlled open state for the section. */
  open: boolean;
  /** Called when an item should toggle. */
  onToggle: () => void;
  /** DOM id for title. */
  titleId: string;
  /** DOM id for panel. */
  panelId: string;
}

/** React context backing sidebar section. */
export const SidebarSectionContext = createContext<SidebarSectionContextValue | undefined>(
  undefined,
);

/** Reads the sidebar section context. */
export function useSidebarSectionContext() {
  const context = useContext(SidebarSectionContext);
  if (!context) {
    throw new Error("SidebarSection compound components must be used within a SidebarSection");
  }
  return context;
}

/** Reads the optional sidebar section context. */
export function useOptionalSidebarSectionContext() {
  return useContext(SidebarSectionContext);
}

"use client";

import {
  type ComponentProps,
  createElement,
  type MouseEvent,
  type MouseEventHandler,
  type ReactNode,
  type Ref,
} from "react";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import { useSidebarChrome } from "./sidebar-context";
import { useSidebarSectionContext } from "./sidebar-section-context";

export type SidebarSectionTitleHeadingLevel = "h1" | "h2" | "h3" | "h4" | "h5" | "h6";

/** Props for sidebar section title. */
export interface SidebarSectionTitleProps extends Omit<ComponentProps<"h2">, "ref" | "onClick"> {
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLElement>;
  /** Called when click occurs. */
  onClick?: MouseEventHandler<HTMLElement>;
  /** Custom handle element for collapsible sections. Pass null to hide. */
  handle?: ReactNode | null;
  /**
   * Heading level rendered for the section title. Default h3 keeps screen-reader heading-rotor
   * navigation predictable. Collapsible sections wrap a button with aria-expanded/aria-controls
   * inside the heading.
   */
  headingLevel?: SidebarSectionTitleHeadingLevel;
}

// Hidden in rail mode: section titles read as truncated text inside a 48px
// rail. The section divider (top border between sibling sections) becomes the
// visual group separator in rail.
const HEADING_CLASS_NAME =
  "px-2 pt-4 pb-1.5 text-muted-foreground text-xs font-mono font-medium uppercase tracking-wider m-0 group-data-[state=rail]/sidebar:hidden";

const TREE_HEADING_CLASS_NAME =
  "px-2 pt-2 pb-1 text-foreground text-sm font-mono font-bold normal-case tracking-normal m-0 group-data-[state=rail]/sidebar:hidden";

/** Section label heading. Disclosure-pattern toggle when collapsible. */
export function SidebarSectionTitle({
  ref,
  children,
  className,
  onClick,
  handle,
  headingLevel = "h3",
  ...rest
}: SidebarSectionTitleProps) {
  const { collapsible, open, onToggle, titleId, panelId } = useSidebarSectionContext();
  const { variant } = useSidebarChrome();
  const isTree = variant === "tree";
  const defaultHandle = <Chevron open={open} size="sm" />;
  const resolvedHandle = handle === undefined ? defaultHandle : handle;
  const headingClassName = isTree ? TREE_HEADING_CLASS_NAME : HEADING_CLASS_NAME;
  const isInteractive = collapsible || !!onClick;

  if (isInteractive) {
    const handleClick = (e: MouseEvent<HTMLButtonElement>) => {
      onClick?.(e);
      if (collapsible && !e.defaultPrevented) onToggle();
    };

    return createElement(
      headingLevel,
      { ref, id: titleId, className: cn(headingClassName, className) },
      <button
        {...(rest as ComponentProps<"button">)}
        type="button"
        className={cn(
          "text-left w-full appearance-none cursor-pointer select-none bg-transparent border-0 p-0 m-0",
          "font-[inherit] text-[inherit]",
          // Intentional asymmetry: only the collapsible branch needs the row
          // layout, because only that branch renders the chevron handle next
          // to the label. A non-collapsible `onClick` title is just label
          // text with a click handler and inherits the heading's block layout.
          collapsible && "flex items-center gap-1",
        )}
        onClick={handleClick}
        aria-expanded={collapsible ? open : undefined}
        aria-controls={collapsible ? panelId : undefined}
      >
        {collapsible && resolvedHandle}
        {children}
      </button>,
    );
  }

  return createElement(
    headingLevel,
    { ...rest, ref, id: titleId, className: cn(headingClassName, className) },
    children,
  );
}

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";
import { useSidebarSectionContext } from "./sidebar-section-context";

/** Props for sidebar section content. */
export interface SidebarSectionContentProps extends ComponentProps<"div"> {}

/**
 * Panel slot for collapsible sections. Wraps items so the title's aria-controls targets a
 * single id.
 */
export function SidebarSectionContent({
  ref,
  className,
  children,
  ...rest
}: SidebarSectionContentProps) {
  const { open, panelId, collapsible } = useSidebarSectionContext();
  const isClosed = collapsible && !open;

  return (
    <div
      {...rest}
      ref={ref}
      id={panelId}
      data-slot="sidebar-section-content"
      data-state={open ? "open" : "closed"}
      aria-hidden={isClosed || undefined}
      inert={isClosed || undefined}
    >
      <div data-slot="sidebar-section-content-inner" className={cn("flex flex-col", className)}>
        {children}
      </div>
    </div>
  );
}

"use client";

import { cva } from "class-variance-authority";
import type {
  AnchorHTMLAttributes,
  ButtonHTMLAttributes,
  MouseEventHandler,
  MouseEvent as ReactMouseEvent,
  ReactNode,
  Ref,
} from "react";
import { isValidElement, useId } from "react";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import { useOptionalSidebar, useSidebarChrome } from "./sidebar-context";
import { resolveSidebarIntent, type SidebarIntent } from "./sidebar-intent";
import { type SidebarVariant, sidebarItemVariants } from "./sidebar-variants";

/** Props for sidebar item render. */
export interface SidebarItemRenderProps {
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLElement>;
  /** Additional class names merged onto the rendered element. */
  className: string;
  /** Disables the item. Adds aria-disabled and removes from tab order. */
  disabled?: boolean;
  /** Called when click occurs. */
  onClick?: MouseEventHandler<HTMLElement>;
  /** ARIA current state forwarded to the rendered element. */
  "aria-current"?: "page";
  /** ARIA disabled state forwarded to the rendered element. */
  "aria-disabled"?: boolean;
  /** Present when the item is selected. */
  "data-selected"?: "";
  /** Intent exposed as a data attribute for styling. */
  "data-intent"?: SidebarIntent;
  /** Navigation item marker consumed by keyboard navigation helpers. */
  "data-diffgazer-navigation-item"?: "button";
  /** Value exposed as a data attribute for styling and selectors. */
  "data-value"?: string;
  /** Present when the item is disabled. */
  "data-disabled"?: "";
  /** Tab index applied to the rendered element. */
  tabIndex?: number;
  /** Variant marker glyph prefix for custom link renderers. */
  itemPrefix?: ReactNode;
}

/** Props for sidebar item shared. */
interface SidebarItemSharedProps {
  /** Marks the item as active. */
  active?: boolean;
  /** Controlled value. */
  value?: string;
  /** intent used by sidebar item shared. */
  intent?: SidebarIntent;
  /** Sidebar subparts (Header, Content, Footer, Trigger). */
  children: ReactNode | ((props: SidebarItemRenderProps) => ReactNode);
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Disables interaction. */
  disabled?: boolean;
}

/** Props for sidebar item as anchor. */
export interface SidebarItemAsAnchorProps
  extends Omit<AnchorHTMLAttributes<HTMLAnchorElement>, "children" | "value">,
    SidebarItemSharedProps {
  /**
   * Rendered element. Items are navigation links by default; pass as="button" for
   * non-navigation actions.
   */
  as?: "a";
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLAnchorElement>;
}

/** Props for sidebar item as button. */
export interface SidebarItemAsButtonProps
  extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, "children" | "disabled" | "value">,
    SidebarItemSharedProps {
  /**
   * Rendered element. Items are navigation links by default; pass as="button" for
   * non-navigation actions.
   */
  as: "button";
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLButtonElement>;
}

/** Props for sidebar item. */
export type SidebarItemProps = SidebarItemAsAnchorProps | SidebarItemAsButtonProps;

/** Class variants for sidebar intent dot. */
export const sidebarIntentDotVariants = cva(
  "inline-block w-1.5 h-1.5 shrink-0 mr-1 group-data-[state=rail]/sidebar:hidden",
  {
    variants: {
      intent: {
        neutral: "bg-muted-foreground",
        info: "bg-info-strong",
        success: "bg-success-strong",
        warning: "bg-warning-strong",
        danger: "bg-error-strong",
        accent: "bg-action",
      },
    },
    defaultVariants: { intent: "neutral" },
  },
);

function flattenText(node: ReactNode): string {
  if (typeof node === "string" || typeof node === "number") return String(node);
  if (Array.isArray(node)) return node.map(flattenText).filter(Boolean).join(" ");
  if (isValidElement<{ children?: ReactNode; "aria-hidden"?: boolean | "true" | "false" }>(node)) {
    const ariaHidden = node.props["aria-hidden"];
    // Skip decorative subtrees so icon glyphs never leak into the rail name.
    if (ariaHidden === true || ariaHidden === "true") return "";
    return flattenText(node.props.children);
  }
  return "";
}

function VariantGlyph({ variant, active }: { variant: SidebarVariant; active: boolean }) {
  // The slot is always rendered so active/inactive rows never reflow.
  if (variant === "caret" || variant === "terminal") {
    return (
      <Chevron
        className={cn(
          "transition-colors motion-reduce:transition-none group-data-[state=rail]/sidebar:hidden",
          active
            ? "text-foreground"
            : "text-transparent group-hover/item:text-muted-foreground group-focus-visible/item:text-muted-foreground",
        )}
      />
    );
  }
  return null;
}

function IntentDot({ intent }: { intent: SidebarIntent }) {
  return (
    <span
      aria-hidden="true"
      data-intent={intent}
      className={sidebarIntentDotVariants({ intent })}
    />
  );
}

/**
 * Nav row. Renders as <a> by default; pass as="button" for actions. Render-prop variant
 * supported.
 */
export function SidebarItem(props: SidebarItemProps): ReactNode {
  const generatedId = useId();
  const { variant, autoTone } = useSidebarChrome();
  const sidebar = useOptionalSidebar();
  const isRail = sidebar?.state === "rail";

  const active = props.active ?? false;
  const disabled = props.disabled ?? false;
  const resolvedValue = props.value ?? generatedId;
  const resolvedIntent = autoTone ? resolveSidebarIntent(props.intent, props.value) : props.intent;

  const guardedClick =
    (onClick?: MouseEventHandler<HTMLElement>): MouseEventHandler<HTMLElement> =>
    (event) => {
      if (disabled) {
        event.preventDefault();
        return;
      }
      onClick?.(event);
    };

  const sharedProps = {
    className: cn(sidebarItemVariants({ variant }), props.className),
    "aria-current": active ? ("page" as const) : undefined,
    "aria-disabled": disabled || undefined,
    "data-selected": active ? ("" as const) : undefined,
    "data-intent": resolvedIntent,
    "data-diffgazer-navigation-item": "button" as const,
    "data-value": resolvedValue,
    "data-disabled": disabled ? ("" as const) : undefined,
    tabIndex: disabled ? -1 : undefined,
  };

  const glyph = <VariantGlyph variant={variant} active={active} />;
  const dot = resolvedIntent ? <IntentDot intent={resolvedIntent} /> : null;
  // Rail mode display:none-hides the visible label/badge, leaving an icon-only
  // row with no accessible name. In rail state, render an sr-only copy of the
  // label so the name survives the collapse; render-prop items own their own
  // markup and supply their own name.
  const railName =
    isRail && typeof props.children !== "function" ? flattenText(props.children) : "";
  const railNameNode = railName ? <span className="sr-only">{railName}</span> : null;
  const itemPrefix = (
    <>
      {railNameNode}
      {dot}
      {glyph}
    </>
  );

  if (typeof props.children === "function") {
    return props.children({
      ref: props.ref as Ref<HTMLElement>,
      disabled: disabled || undefined,
      onClick: guardedClick(props.onClick as MouseEventHandler<HTMLElement> | undefined),
      itemPrefix,
      ...sharedProps,
    });
  }

  if (props.as === "button") {
    const {
      active: _active,
      value: _value,
      intent: _intent,
      children,
      className: _className,
      disabled: _disabled,
      as: _as,
      ref,
      onClick,
      ...buttonProps
    } = props;
    return (
      <button
        {...buttonProps}
        ref={ref}
        type="button"
        disabled={disabled}
        {...sharedProps}
        onClick={guardedClick(onClick)}
      >
        {itemPrefix}
        {children}
      </button>
    );
  }

  const {
    active: _active,
    value: _value,
    intent: _intent,
    children,
    className: _className,
    disabled: _disabled,
    as: _as,
    ref,
    onClick,
    ...anchorProps
  } = props;

  return (
    // biome-ignore lint/a11y/noStaticElementInteractions: this is a navigation anchor; href is provided by the consumer via anchorProps, so the onClick only guards the disabled state.
    <a
      {...anchorProps}
      ref={ref}
      {...sharedProps}
      // biome-ignore lint/a11y/useValidAnchor: href is supplied by the consumer through anchorProps (spread), which Biome cannot see; the onClick guards disabled navigation rather than replacing the href.
      onClick={(event: ReactMouseEvent<HTMLAnchorElement>) => {
        if (disabled) {
          event.preventDefault();
          return;
        }
        onClick?.(event);
      }}
    >
      {itemPrefix}
      {children}
    </a>
  );
}

